import{_ as a,o as e,c as o,a3 as l}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"📋 会话管理","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/sessions.md","filePath":"user-guide/tools/llm-chat/sessions.md","lastUpdated":1778221347000}'),r={name:"user-guide/tools/llm-chat/sessions.md"};function s(i,t,n,d,h,c){return e(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="📋-会话管理" tabindex="-1">📋 会话管理 <a class="header-anchor" href="#📋-会话管理" aria-label="Permalink to &quot;📋 会话管理&quot;">​</a></h1><p>会话 (Session) 是 LLM Chat 中管理对话历史的基本单位。每个会话保存了一棵完整的<strong>消息树</strong>，包含所有分支路径。</p><h2 id="创建会话" tabindex="-1">创建会话 <a class="header-anchor" href="#创建会话" aria-label="Permalink to &quot;创建会话&quot;">​</a></h2><h3 id="快速创建" tabindex="-1">快速创建 <a class="header-anchor" href="#快速创建" aria-label="Permalink to &quot;快速创建&quot;">​</a></h3><p>点击右侧会话列表顶部的 ➕ 按钮，系统会立即使用<strong>当前选中的智能体 (Agent)</strong> 创建新的空会话——没有弹窗，一步到位。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>创建会话时自动使用当前 Agent。如果当前没有选中任何 Agent，则使用最近使用过的默认 Agent。</p></div><h3 id="默认名称" tabindex="-1">默认名称 <a class="header-anchor" href="#默认名称" aria-label="Permalink to &quot;默认名称&quot;">​</a></h3><p>会话会以当前时间自动命名（例如 <code>会话 2026-05-08 10:30:00</code>）。你可以在会话上右键选择「重命名」来修改。另外，启用「话题命名」功能后，系统会在积累足够消息后自动生成更具描述性的标题。</p><blockquote><p>TODO: 截图 — 会话列表面板，标注创建按钮</p></blockquote><h2 id="切换会话" tabindex="-1">切换会话 <a class="header-anchor" href="#切换会话" aria-label="Permalink to &quot;切换会话&quot;">​</a></h2><p>右侧的「会话列表」面板展示了所有历史会话：</p><ul><li><strong>按最后更新时间排序</strong>：最近使用的会话排在最前面</li><li><strong>显示 Agent 图标</strong>：每条会话右侧会显示该会话最近使用的 Agent 头像</li><li><strong>消息数量</strong>：显示会话中的消息总数</li><li><strong>点击切换</strong>：点击任意会话条目即可切换到该会话</li></ul><p>切换会话时，系统采用<strong>按需加载</strong>策略——只加载当前活跃会话的完整详情，其他会话仅保留轻量级索引，从而显著提升启动速度和切换性能。</p><blockquote><p>TODO: 截图 — 会话列表面板</p></blockquote><h2 id="分组管理" tabindex="-1">分组管理 <a class="header-anchor" href="#分组管理" aria-label="Permalink to &quot;分组管理&quot;">​</a></h2><p>会话列表目前保持平铺展示。你可以通过以下方式管理多个会话：</p><ul><li><strong>重命名</strong>：右键点击会话条目 → 重命名</li><li><strong>排序</strong>：系统按最后更新时间自动排序</li><li><strong>清理</strong>：批量删除不再需要的会话</li></ul><h2 id="搜索历史会话" tabindex="-1">搜索历史会话 <a class="header-anchor" href="#搜索历史会话" aria-label="Permalink to &quot;搜索历史会话&quot;">​</a></h2><p>右侧会话列表顶部提供搜索框，支持按会话名称搜索。输入关键词后列表会实时过滤匹配的会话。</p><p>此外，在对话视图下你也可以使用 <code>ChatSearchPanel</code> 在<strong>当前会话内部</strong>搜索消息内容：</p><ul><li>按关键字搜索当前会话的所有消息</li><li>搜索结果高亮显示</li><li>点击结果自动滚动到对应消息位置</li></ul><h2 id="删除会话" tabindex="-1">删除会话 <a class="header-anchor" href="#删除会话" aria-label="Permalink to &quot;删除会话&quot;">​</a></h2><ol><li>右键点击要删除的会话 → 选择「删除」</li><li>如果启用了删除确认弹窗，点击确认以完成删除</li><li>删除后无法恢复（文件将被移入系统回收站）</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>删除会话会同时删除该会话下的所有消息和分支，请谨慎操作。</p></div><h3 id="清空所有会话" tabindex="-1">清空所有会话 <a class="header-anchor" href="#清空所有会话" aria-label="Permalink to &quot;清空所有会话&quot;">​</a></h3><p>在会话列表顶部的菜单中可以选择「清空所有会话」，此操作会删除全部历史会话并重置状态。</p><h2 id="会话的数据结构" tabindex="-1">会话的数据结构 <a class="header-anchor" href="#会话的数据结构" aria-label="Permalink to &quot;会话的数据结构&quot;">​</a></h2><p>为了实现极致的性能，LLM Chat 采用了<strong>索引与详情分离</strong>的存储架构：</p><table tabindex="0"><thead><tr><th>部分</th><th>内容</th><th>加载策略</th></tr></thead><tbody><tr><td><strong>索引 (Index)</strong></td><td>会话 ID、名称、消息数、最后更新时间、Agent 标识</td><td>启动时全量加载，用于极速渲染列表</td></tr><tr><td><strong>详情 (Detail)</strong></td><td>完整的消息节点树、当前活动分支、撤销/重做栈</td><td><strong>按需加载</strong>：仅在你点击切换到该会话时才从磁盘读取</td></tr></tbody></table><h3 id="索引自愈机制" tabindex="-1">索引自愈机制 <a class="header-anchor" href="#索引自愈机制" aria-label="Permalink to &quot;索引自愈机制&quot;">​</a></h3><p>系统在后台会定期运行自愈程序，自动检测并修复因异常关闭可能导致的索引损坏（如消息计数不准）。</p><p>这种设计确保了即使你的历史记录中积累了数千个会话，应用依然能保持毫秒级的启动和切换速度。</p><h2 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h2><ul><li><a href="./messages">消息操作</a> — 了解会话内的消息编辑、分支管理</li><li><a href="./export-import">导出与导入</a> — 将会话导出为 Markdown 或 JSON</li></ul>',34)])])}const g=a(r,[["render",s]]);export{u as __pageData,g as default};
